@st.cache_data
def load_locations() -> pd.DataFrame:
    frames = [pd.read_csv(path) for path in LOCATIONS_METADATA_PATHS if path.exists()]
    if not frames:
        return pd.DataFrame(columns=["location", "lat", "lon", "elevation", "rainfall_zone"])

    # Coordinates live in the base metadata, while the rainfall-zone enrichment
    # is written to the daily-zonal metadata. Merge both instead of returning the
    # first file found (which previously made every zone appear as "Unknown").
    base = next(
        (
            frame.copy()
            for frame in frames
            if {"location", "lat", "lon"}.issubset(frame.columns)
        ),
        pd.DataFrame(),
    )
    if base.empty:
        return pd.DataFrame(columns=["location", "lat", "lon", "elevation", "rainfall_zone"])

    keep = [col for col in ["location", "lat", "lon", "elevation"] if col in base.columns]
    frame = base[keep].copy()
    frame["location"] = frame["location"].astype(str).str.strip()

    zone_frames = []
    for source in frames:
        if {"location", "rainfall_zone"}.issubset(source.columns):
            zones = source[["location", "rainfall_zone"]].copy()
            zones["location"] = zones["location"].astype(str).str.strip()
            zones["rainfall_zone"] = zones["rainfall_zone"].map(normalize_rainfall_zone)
            zones = zones.loc[zones["rainfall_zone"] != "Unknown"]
            zone_frames.append(zones)
    if zone_frames:
        zone_lookup = (
            pd.concat(zone_frames, ignore_index=True)
            .drop_duplicates(subset=["location"], keep="last")
        )
        frame = frame.merge(zone_lookup, on="location", how="left")
    else:
        frame["rainfall_zone"] = "Unknown"

    frame["rainfall_zone"] = frame["rainfall_zone"].map(normalize_rainfall_zone)
    if "elevation" not in frame.columns:
        frame["elevation"] = None
    return (
        frame.dropna(subset=["location", "lat", "lon"])
        .drop_duplicates(subset=["location"])
        .sort_values("location")
        .reset_index(drop=True)
    )


@st.cache_resource
def load_prediction_runtime() -> tuple[dict | None, object | None, str | None]:
    try:
        import joblib
        from catboost import Pool
    except Exception as exc:  # pragma: no cover - local presentation dependency
        return None, None, f"Prediction runtime is missing: {exc}"

    if not WINNER_MODEL_PATH.exists():
        return None, None, "Winner model artifact is missing."

    try:
        artifact = joblib.load(WINNER_MODEL_PATH)
    except Exception as exc:  # pragma: no cover - local artifact dependency
        return None, None, f"Winner model could not be loaded: {exc}"

    if isinstance(artifact, dict):
        model = artifact.get("model")
        features = artifact.get("features") or FEATURES
        categorical = artifact.get("categorical_features") or METADATA.get("categorical_features", ["location"])
        fill_values = artifact.get("numeric_fill_values") or METADATA.get("numeric_fill_values", {})
        threshold = float(artifact.get("threshold") or THRESHOLD)
    else:
        model = artifact
        features = list(getattr(model, "feature_names_", FEATURES))
        categorical = METADATA.get("categorical_features", ["location"])
        fill_values = METADATA.get("numeric_fill_values", {})
        threshold = THRESHOLD

    if model is None or not features:
        return None, None, "Winner model contract is incomplete."

    return (
        {
            "model": model,
            "features": features,
            "categorical": categorical,
            "fill_values": fill_values,
            "threshold": threshold,
        },
        Pool,
        None,
    )


